  pickedTeamName: string;
  /** @nullable */
  pickedTeamLogoUrl?: string | null;
  result: PickEmDailyPickDetailResult;
  homeTeam: PickEmDailyPickDetailTeam;
  awayTeam: PickEmDailyPickDetailTeam;
