export interface PickEmDailyBreakdown {
  /** YYYY-MM-DD date in ET */
  date: string;
  correct: number;
  picked: number;
}

export interface PickEmLeaderboardEntry {
  rank: number;
  userId: number;
  username: string;
  /** @nullable */
  displayName?: string | null;
  correct: number;
  picked: number;
  picks: PickEmPlayerPick[];
  /** Per-day breakdown; present only for weekly pick-em pools */
  dailyBreakdown?: PickEmDailyBreakdown[];
  /**
     * Player's tiebreaker runs guess (MLB pools only)
     * @nullable
     */
  tiebreakerRunsGuess?: number | null;
  /**
     * Player's tiebreaker strikeouts guess (MLB pools only)
     * @nullable
     */
  tiebreakerStrikeoutsGuess?: number | null;
  /**
     * Absolute difference between runs guess and actual (null if no actual yet)
     * @nullable
     */
  tiebreakerRunsDiff?: number | null;
  /**
     * Player's tiebreaker shots on goal guess (NHL weekly pools only)
     * @nullable
     */
  tiebreakerShotsOnGoalGuess?: number | null;
  /**
     * Player's tiebreaker penalty minutes guess (NHL weekly pools only)
     * @nullable
     */
  tiebreakerPenaltyMinutesGuess?: number | null;
  /**
     * Combined absolute error |shotsGuess - actualShots| + |pimGuess - actualPim| (null if no actual yet)
     * @nullable
     */
  tiebreakerNhlDiff?: number | null;
  /**
     * Prize amount won; populated on winning entries once the period is fully graded; null otherwise
     * @nullable
     */
  prizeWon?: number | null;
}

export interface PickEmLeaderboard {
  poolId: number;
  week: number;
  /** True for weekly pick-em pools (Mon–Sun accumulation) */
  isWeekly?: boolean;
  /**
     * Monday of the current scoring week (YYYY-MM-DD); null for non-weekly pools
     * @nullable
     */
  weekStart?: string | null;
  /**
     * Sunday of the current scoring week (YYYY-MM-DD); null for non-weekly pools
     * @nullable
     */
  weekEnd?: string | null;
  /**
     * WC phase returned (group_stage, knockout_stage); null for non-WC sports
     * @nullable
     */
  phase?: string | null;
  /**
     * Total schedulable games for the active phase (WC only); null for non-WC
     * @nullable
     */
  totalGames?: number | null;
  /**
     * Games with a final result in the active phase (WC only); use as pick-accuracy denominator; null for non-WC
     * @nullable
     */
  completedGames?: number | null;
  games: PickEmLeaderboardGame[];
  entries: PickEmLeaderboardEntry[];
  /**
     * Runs scored in the tiebreaker game (last game on the slate) once final (MLB pools only; null if not applicable or game not yet final)
     * @nullable
     */
  tiebreakerActualRuns?: number | null;
  /**
     * Strikeouts in the tiebreaker game (last game on the slate) via MLB Stats API (MLB pools only; null if not applicable, game unmatched, or fetch failed)
     * @nullable
     */
  tiebreakerActualStrikeouts?: number | null;
  /**
     * Combined shots on goal in the tiebreaker game once final (NHL weekly pools only; null if not applicable or game not yet final)
     * @nullable
     */
  tiebreakerActualShotsOnGoal?: number | null;
  /**
     * Combined penalty minutes in the tiebreaker game once final (NHL weekly pools only; null if not applicable or game not yet final)
     * @nullable
     */
  tiebreakerActualPenaltyMinutes?: number | null;
}

